# Nested dictionary structure for IoT sensor network
iot_devices = {
 'sensor_001': {
 'location': 'Living Room',
 'type': 'temperature',
 'readings': [22.5, 23.0, 22.8],
 'status': 'active'
 },
 'sensor_002': {
 'location': 'Bedroom',
 'type': 'humidity',
 'readings': [65, 67, 64],
 'status': 'active'
 },
 'sensor_003': {
 'location': 'Kitchen',
 'type': 'temperature',
 'readings': [24.1, None, 23.9], # None = missing reading
 'status': 'error'
 }
}

# O(1) lookup by device ID
def get_device_readings(device_id):
 device = iot_devices.get(device_id)
 if device is None:
 return f"Device {device_id} not found"
 valid_readings = [r for r in device['readings'] if r is not None]
 return {
 'device': device_id,
 'location': device['location'],
 'average': sum(valid_readings)/len(valid_readings) if valid_readings else None
 }

print(get_device_readings('sensor_001'))
print(get_device_readings('sensor_003'))
